const e=document.getElementById("translateBtn");let c=!1;async function u(n){const t=document.createTreeWalker(n,NodeFilter.SHOW_TEXT,null);let o;const a=[];for(;o=t.nextNode();)o.nodeValue.trim()&&a.push(o);for(const l of a)try{const d=await(await fetch("https://translate.googleapis.com/translate_a/single?client=gtx&sl=zh-Hant&tl=en&dt=t&q="+encodeURIComponent(l.nodeValue))).json();let s="";for(const i of d[0])s+=i[0];l.nodeValue=s}catch(r){console.error("Node translation failed",r)}}e?.addEventListener("click",async()=>{if(c)location.reload();else{e.textContent,e.textContent="Translating...",e.disabled=!0;const n=[document.querySelector("header"),document.querySelector("main"),document.querySelector("footer")];for(const t of n)t&&await u(t);c=!0,e.textContent="中文",e.disabled=!1}});
